mapper.select:
SELECT chunk.knowledge_base_id, chunk.id AS chunk_id, chunk.document_id, chunk.chunk_index, document.file_name, chunk.chunk_text, 1 - (embedding.embedding <=> CAST(#{embedding} AS vector)) AS score FROM chunk_embeddings AS embedding JOIN document_chunks AS chunk ON chunk.id = embedding.chunk_id AND chunk.knowledge_base_id = embedding.knowledge_base_id JOIN documents AS document ON document.id = embedding.document_id AND document.knowledge_base_id = embedding.knowledge_base_id WHERE embedding.knowledge_base_id IN
#{knowledgeBaseId}
AND chunk.status = 'READY' AND chunk.deleted = FALSE AND document.status = 'READY' ORDER BY embedding.embedding <=> CAST(#{embedding} AS vector) LIMIT #{limit}

WITH seeds AS ( SELECT knowledge_base_id, document_id, chunk_index FROM document_chunks WHERE knowledge_base_id IN
#{knowledgeBaseId}
AND id IN
#{chunkId}
) SELECT DISTINCT chunk.knowledge_base_id, chunk.id AS chunk_id, chunk.document_id, chunk.chunk_index, document.file_name, chunk.chunk_text AS text FROM document_chunks AS chunk JOIN documents AS document ON document.id = chunk.document_id AND document.knowledge_base_id = chunk.knowledge_base_id WHERE chunk.knowledge_base_id IN
#{knowledgeBaseId}
AND chunk.status = 'READY' AND chunk.deleted = FALSE AND document.status = 'READY' AND EXISTS ( SELECT 1 FROM seeds WHERE seeds.knowledge_base_id = chunk.knowledge_base_id AND seeds.document_id = chunk.document_id AND chunk.chunk_index BETWEEN seeds.chunk_index - #{radius} AND seeds.chunk_index + #{radius} ) ORDER BY chunk.document_id, chunk.chunk_index
